const body = $input.first().json.body;
const { report_type, data, metrics, filters } = body;

const chartOptions = ['line', 'bar', 'pie', 'funnel', 'table'];

const prompt = `Kamu adalah analis data penjualan pakaian.

Tipe laporan: ${report_type}
Filter periode: dari ${filters?.from || 'awal'} sampai ${filters?.to || 'sekarang'}
${filters?.sales_id ? 'Filter sales_id: ' + filters.sales_id : ''}

Metrics:
${JSON.stringify(metrics, null, 2)}

Data sample (maksimal 10 baris):
${JSON.stringify(Array.isArray(data) ? data.slice(0,10) : data, null, 2)}

Analisa data di atas dan kembalikan JSON valid berikut:
{
  "chart_type": "${chartOptions.join('|')}",
  "summary": "ringkasan 2-3 kalimat Bahasa Indonesia",
  "anomalies": [{"metric": "", "actual": 0, "expected": 0, "variance_pct": 0, "description": ""}],
  "recommendation": "1 kalimat saran tindakan konkret"
}

Kembalikan JSON valid saja, tanpa teks lain.`;

return [{ json: { prompt, report_type } }];

const raw = $input.first().json.message.content.trim();

// Fallback response
const fallback = {
  chart_type: 'bar',
  summary: 'Data tersedia namun analisis AI sedang tidak tersedia.',
  anomalies: [],
  recommendation: 'Silakan refresh atau coba beberapa saat lagi.'
};

let parsed;
try {
  // Strip markdown code block if present
  const cleaned = raw.replace(/```json?/g, '').replace(/```/g, '').trim();
  parsed = JSON.parse(cleaned);
} catch(e) {
  parsed = fallback;
}

// Validate required fields
if (!parsed.chart_type || !parsed.summary) {
  parsed = { ...fallback, ...parsed };
}

// Ensure anomalies is array
if (!Array.isArray(parsed.anomalies)) {
  parsed.anomalies = [];
}

return [{ json: parsed }];
